// ====================================================
// CLEAN & OPTIMIZE INCOMING MARKET DATA
// ====================================================

for (const item of $input.all()) {

  // Extract raw text from possible fields
  let rawText = item.json.content || item.json.body || item.json.text || '';

  // Remove HTML tags
  let cleanedText = rawText.replace(/<[^>]*>/g, ' ');

  // Normalize whitespace
  cleanedText = cleanedText.replace(/\s+/g, ' ').trim();

  // Truncate excessively large payloads
  if (cleanedText.length > 6000) {
    cleanedText = cleanedText.substring(0, 6000) + ' ... [Truncated]';
  }

  // Store optimized payload
  item.json.optimized_payload = cleanedText;
}

return $input.all();

// ====================================================
// VALIDATE & PARSE AI JSON RESPONSE
// ====================================================

for (const item of $input.all()) {

  // Get raw AI output
  let rawLlmOutput =
    item.json.output ||
    item.json.text ||
    item.json.response ||
    '';

  let parsedData = {};

  try {

    // Remove markdown code blocks
    rawLlmOutput = rawLlmOutput
      .replace(/```json/g, '')
      .replace(/```/g, '')
      .trim();

    // Remove accidental Google artifacts
    rawLlmOutput = rawLlmOutput.replace(
      /http:\/\/googleusercontent\.com\/immersive_entry_chip\/0\S*/g,
      ''
    );

    // Parse JSON safely
    parsedData = JSON.parse(rawLlmOutput);

  } catch (error) {

    // Prevent workflow failure
    item.json.error = 'Failed to parse LLM output as JSON';

    item.json.rawLlmOutput = rawLlmOutput;

    // Safe fallback response
    parsedData = {
      competitor_name: 'Unknown',
      impact_level: 'Low',
      summary_one_sentence: 'AI parsing failure occurred.',
      action_required: false,
      recommended_response: 'Manual review required.'
    };
  }

  // Store validated output
  item.json.output = parsedData;
}

return $input.all();

